import { OpenAIEmbedding } from 'llamaindex/embeddings-openai';

const documents = await SimpleDirectoryReader.fromDirectory('./my-repo');
const embedModel = new OpenAIEmbedding({ model: 'text-embedding-3-small' });

const index = await VectorStoreIndex.fromDocuments(documents, {
  embedModel,
});

const queryEngine = index.asQueryEngine({ similarityTopK: 5 });

const response = await queryEngine.query({
  query: 'Implement rate limiting for API endpoints',
  chatHistory: [],
});
