from vex import verify

class CodingAgent:
    def __init__(self, query_engine):
        self.query_engine = query_engine

    @verify(guards=['code_correctness', 'security_vulnerability_scanning'])
    def generate_fix(self, bug_description: str) -> str:
        return str(self.query_engine.query(bug_description))

    @verify(guards=['no_credential_leakage', 'dependency_safety'])
    def validate_execution(self, code: str, test_results: dict) -> str:
        # Sandbox execution + validation
        return f"Code verified: {len(code)} chars"

agent = CodingAgent(query_engine)

# Iterative debugging
fix = agent.generate_fix("Null pointer in user service")
result = agent.validate_execution(fix, {'passed': True})
